import React from 'react';
import { Carousel } from 'antd';

const contentStyle = {
  position: 'relative',
};

const textOverlayStyle = {
  position: 'absolute',
  top: '50%',
  left: '0',
  right: '0',
  zIndex: 10,
  textAlign: 'center', // Center the text horizontally
  padding: '10px', // Add padding for better appearance
  borderRadius: '5px', // Add border radius for better appearance
  transform: 'translateY(-50%)', // Move the text up by half its height to vertically center it
};

const imageStyle = {
  width: '100%',
  height: '300px', // Adjusted height
  objectFit: 'cover',
};

const HomeCarousel = () => (
  <Carousel autoplay style={{ margin: '40px' }}>
    <div style={contentStyle}>
      <img src="/carousel1.avif" alt="Carousel 1" style={imageStyle} />
      <div style={textOverlayStyle}>
        WELCOME SHOP NOW
      </div>
    </div>
    <div style={contentStyle}>
      <img src="/carousel2.avif" alt="Carousel 2" style={imageStyle} />
      <div style={textOverlayStyle}>
        WELCOME SHOP NOW
      </div>
    </div>
    <div style={contentStyle}>
      <img src="/carousel3.avif" alt="Carousel 3" style={imageStyle} />
      <div style={textOverlayStyle}>
        WELCOME SHOP NOW
      </div>
    </div>
    <div style={contentStyle}>
      <img src="/carousel4.avif" alt="Carousel 4" style={imageStyle} />
      <div style={textOverlayStyle}>
        WELCOME SHOP NOW
      </div>
    </div>
  </Carousel>
);

export default HomeCarousel;
